mapper.select:
SELECT employee.user_id , employee.company_id , employee.employee_code , employee.employee_name , employee.no_use , employee.employee_no , IFNULL(employee.myself, 2) AS myself , employee.birth , employee.sex , employee.email , employee.mobile , employee.zipcode , employee.address1 , employee.address2 , employee.depart , employee.title , employee_checkup.employee_checkup_id , employee_checkup.company_checkup_id , employee_checkup.vip , employee_checkup.support_type , employee_checkup.company_checkup_type_id , employee_checkup.special_checkup , employee_checkup.special_checkup_memo , employee_checkup.notes , company_checkup.checkup_year , company.company_name FROM employee_checkup JOIN employee ON employee_checkup.user_id = employee.user_id JOIN company_checkup ON employee_checkup.company_checkup_id = company_checkup.company_checkup_id JOIN company ON company_checkup.company_id = company.company_id AND company.deleted_at IS NULL WHERE employee_checkup.deleted_at IS NULL
AND company_checkup.checkup_year = #{checkupYear}
AND employee_checkup.company_checkup_id = #{companyCheckupId}
AND company_checkup.company_id = #{companyId} AND company_checkup.checkup_year = #{checkupYear}
ORDER BY employee.employee_code, myself, employee_checkup.employee_checkup_id

SELECT E.user_id , E.company_id , C.company_name , E.employee_code , E.employee_name , E.no_use , E.employee_no , IFNULL(E.myself, 2) AS myself , E.birth , E.sex , E.email , E.mobile , E.zipcode , E.address1 , E.address2 , E.depart , E.title , EC.employee_checkup_id , EC.company_checkup_id , EC.vip , EC.support_type , EC.company_checkup_type_id , EC.special_checkup , EC.special_checkup_memo , EC.notes , CC.checkup_year , CCT.company_checkup_type_name , CCT.company_checkup_type_code FROM employee_checkup EC JOIN employee E ON EC.user_id = E.user_id JOIN company_checkup CC ON EC.company_checkup_id = CC.company_checkup_id JOIN company C ON CC.company_id = C.company_id JOIN company_checkup_type CCT ON EC.company_checkup_type_id = CCT.company_checkup_type_id WHERE EC.deleted_at IS NULL
AND EC.company_checkup_id = #{companyCheckupId}
AND CC.company_id = (SELECT company_id FROM company_manager WHERE user_id = #{userId}) AND CC.checkup_year = #{checkupYear}
ORDER BY E.employee_code, myself, EC.employee_checkup_id

