UPDATE employee
SET company_id      = #{companyId}
  , employee_code   = #{employeeCode}
  , employee_name   = #{employeeNameCrypt}
  , no_use          = #{noUse}
  , employee_no     = #{employeeNo}
  , myself          = #{myself}
  , birth           = #{birth}
  , sex             = #{sex}
  , email           = #{email}
  , mobile          = #{mobile}
  , zipcode         = #{zipcode}
  , address1        = #{address1}
  , address2        = #{address2}
  , depart          = #{depart}
  , title           = #{title}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE user_id = #{userId}

UPDATE employee_checkup
SET company_checkup_id      = #{companyCheckupId}
  , vip                     = #{vip}
  , support_type            = #{supportType}
  , company_checkup_type_id = #{companyCheckupTypeId}
  , special_checkup         = #{specialCheckup}
  , special_checkup_memo    = #{specialCheckupMemo}
  , notes                   = #{notes}
  , notok_guide             = #{notokGuide}
  , notok_reserve           = #{notokReserve}
  , notok_urge              = #{notokUrge}
  , notok_updated_at        = #{notokUpdatedAt}
  , notok_updated_user_id   = #{notokUpdatedUserId}
  , updated_at              = NOW()
  , updated_user_id         = #{sessionUserId}
WHERE employee_checkup_id = #{employeeCheckupId}

UPDATE employee_checkup
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE employee_checkup_id = #{employeeCheckupId}

