SELECT COUNT(*) AS check_id , employee.company_id , employee.employee_code , employee.employee_name , employee.myself , company_checkup.checkup_year FROM employee_checkup JOIN employee ON employee_checkup.user_id = employee.user_id JOIN company_checkup ON employee_checkup.company_checkup_id = company_checkup.company_checkup_id JOIN company ON company_checkup.company_id = company.company_id AND company.deleted_at IS NULL WHERE company_checkup.company_id = #{companyId} AND employee_checkup.deleted_at IS NULL AND employee.employee_code = #{employeeCode}
AND employee.myself = 1 AND company_checkup.checkup_year = #{checkupYear}
AND employee.employee_name = #{employeeNameCrypt} AND company_checkup.checkup_year = #{checkupYear}

