UPDATE employee_checkup
SET terms_of_use       = #{termsOfUse}
  , privacy_policy     = #{privacyPolicy}
  , collection_and_use = #{collectionAndUse}
  , updated_at         = NOW()
  , updated_user_id    = #{sessionUserId}
WHERE employee_checkup_id = sf_employee_checkup_id(#{sessionUserId}, #{checkupYear})

UPDATE employee
SET employee_name   = #{employeeNameCrypt}
  , birth           = #{birth}
  , sex             = #{sex}
  , email           = #{email}
  , mobile          = #{mobile}
  , zipcode         = #{zipcode}
  , address1        = #{address1}
  , address2        = #{address2}
  , updated_at      = NOW()
  , updated_user_id = #{sessionUserId}
WHERE user_id = #{userId}

UPDATE employee_checkup
SET company_checkup_type_id = #{companyCheckupTypeId}
  , updated_at              = NOW()
  , updated_user_id         = #{sessionUserId}
WHERE employee_checkup_id = #{employeeCheckupId}
  AND user_id = #{userId}
  AND support_type = 1

