    FROM employee E
                 JOIN employee_checkup EC ON E.user_id = EC.user_id
                 JOIN company_checkup CC
            ON EC.company_checkup_id = CC.company_checkup_id AND CC.checkup_year = #{checkupYear}
    WHERE E.employee_code = #{employeeCode}
      AND E.mobile = #{mobile}
      AND E.employee_name = #{employeeNameCrypt}
      AND E.myself = 1
      AND E.no_use = 0
      AND E.deleted_at IS NULL
    LIMIT 0, 1
